function slugify(category: string, name: string): string {
  const prefix = category.toLowerCase().replace(/\s+/g, '-');
  const n = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
  return `${prefix}-${n}`;
}

