export function getToolBySlug(slug: string): AINsfwTool | undefined {
  return AI_NSFW_TOOLS.find(t => t.slug === slug);
}

export function getToolsByCategory(category: string): AINsfwTool[] {
  if (category === 'All') return AI_NSFW_TOOLS;
  return AI_NSFW_TOOLS.filter(t => t.category === category);
}
